  ('public-health-specialist-moex-00127', 'public-health-specialist', 'public-health-specialist-moex-114-de898702', 'sub-public-health-specialist-05', NULL, 'single_choice', '有關病人之告知後同意權利，在醫療法與病人自主權利法之規範不盡相同，下列有關兩者差異之 敘述何者錯誤？', '["病人自主權利法要求醫師對於無行為能力之病人，仍應以適當方式告知本人相關資訊；但醫療 法並無類似之規定", "病人自主權利法規定應將相關資訊告知病人本人，且在病人未明示反對時始得告知其關係人； 但依醫療法規定，告知對象則可直接為病人或其關係人", "依病人自主權利法與醫療法之規定，手術同意書之簽署可為病人或其關係人", "病人自主權利法規定病人對於醫師在治療上可能產生之利益衝突有知情權利；醫療法則無類似 之規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:35+00:00", "source_pdf_sha1": "4c56c8081c0b", "answer_pdf_sha1": "348d6a59f049", "source_family": "moex-gov-tw", "moex": {"exam_code": "114100", "c": "108", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "衛生法規及倫理", "year": "114", "exam_name": "114年第二次專技人員高等考試營養師、護理師、社會工作師考試、114年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "publichealth", "db_exam_id": "public-health-specialist"}'::jsonb, NULL),
